package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
)

type Book struct {
	ISBN      string `json:"isbn"`
	Title     string `json:"title"`
	Author    string `json:"author"`
	Available bool   `json:"available"`
}

var catalog = map[string]Book{
	"978-0141036144": {ISBN: "978-0141036144", Title: "1984", Author: "George Orwell", Available: true},
	// TODO: add book with isbn "978-0061120084"
}

func bookHandler(w http.ResponseWriter, r *http.Request) {
	isbn := r.URL.Query().Get("isbn")
	book, ok := catalog[isbn]
	if !ok {
		w.WriteHeader(http.StatusNotFound)
		fmt.Fprintln(w, `{"error":"book not found"}`)
		return
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(book)
}

func main() {
	for _, isbn := range []string{"978-0141036144", "978-0061120084", "978-9999999999"} {
		req := httptest.NewRequest("GET", "/?isbn="+isbn, nil)
		w := httptest.NewRecorder()
		bookHandler(w, req)
		fmt.Printf("[%d] %s", w.Code, w.Body.String())
	}
}

